            reference.DigestMethod = SignedXml.XmlDsigSHA1Url;

            var envelopedTransform = new XmlDsigEnvelopedSignatureTransform();
            reference.AddTransform(envelopedTransform);

            var excC14NTransform = new XmlDsigExcC14NTransform();
            reference.AddTransform(excC14NTransform);

            signedXml.AddReference(reference);

            // Add KeyInfo with X509 certificate
            var keyInfo = new KeyInfo();
            var keyInfoData = new KeyInfoX509Data(certificate);
            keyInfo.AddClause(keyInfoData);
            signedXml.KeyInfo = keyInfo;

            signedXml.ComputeSignature();

            var signatureElement = signedXml.GetXml();

            // Insert signature after Issuer element or as first child
            var issuerNode = doc.DocumentElement.GetElementsByTagName("Issuer", SamlAssertionNamespace);
            if (issuerNode.Count > 0)
            {
                doc.DocumentElement.InsertAfter(signatureElement, issuerNode[0]);
            }
            else
            {
                doc.DocumentElement.PrependChild(signatureElement);
            }

            return doc;
        }

        public bool VerifySignature(XmlDocument doc)
        {
            var signedXml = new SignedXml(doc);
            var signatureNode = doc.GetElementsByTagName("Signature", SignedXml.XmlDsigNamespaceUrl);

            if (signatureNode.Count == 0)
                return false;

            signedXml.LoadXml((XmlElement)signatureNode[0]);
            return signedXml.CheckSignature();
        }

