        /// <summary>
        /// Encrypts sensitive attributes within a SAML XML document using TripleDES.
        /// Creates EncryptedAttribute elements as per SAML 2.0 spec.
        /// </summary>
        public XmlDocument EncryptSamlAttributes(XmlDocument samlDoc, 
            Dictionary<string, string> sensitiveAttributeNames, byte[] tripleDesKey, byte[] tripleDesIv)
        {
            const string SamlAssertionNamespace = "urn:oasis:names:tc:SAML:2.0:assertion";
            const string XencNamespace = "http://www.w3.org/2001/04/xmlenc#";

            var attributeStatements = samlDoc.GetElementsByTagName("AttributeStatement", SamlAssertionNamespace);
            if (attributeStatements.Count == 0)
                return samlDoc;

            foreach (XmlNode attrStatement in attributeStatements)
            {
                var attributes = attrStatement.SelectNodes("saml:Attribute", CreateNamespaceManager(samlDoc));
                if (attributes == null) continue;

                var toReplace = new List<(XmlNode original, XmlNode replacement)>();

                foreach (XmlNode attr in attributes)
                {
                    var nameAttr = attr.Attributes?["Name"]?.Value;
                    if (nameAttr == null || !sensitiveAttributeNames.ContainsKey(nameAttr))
                        continue;

                    // Encrypt the attribute XML
                    var attributeXml = attr.OuterXml;
                    var encryptedValue = EncryptWithTripleDes(attributeXml, tripleDesKey, tripleDesIv);

                    // Create EncryptedAttribute element
                    var encryptedAttribute = samlDoc.CreateElement("saml", "EncryptedAttribute", SamlAssertionNamespace);

                    var encryptedData = samlDoc.CreateElement("xenc", "EncryptedData", XencNamespace);
                    encryptedData.SetAttribute("Type", "http://www.w3.org/2001/04/xmlenc#Element");

                    var encryptionMethod = samlDoc.CreateElement("xenc", "EncryptionMethod", XencNamespace);
                    encryptionMethod.SetAttribute("Algorithm", "http://www.w3.org/2001/04/xmlenc#tripledes-cbc");
                    encryptedData.AppendChild(encryptionMethod);

                    var cipherData = samlDoc.CreateElement("xenc", "CipherData", XencNamespace);
                    var cipherValue = samlDoc.CreateElement("xenc", "CipherValue", XencNamespace);
                    cipherValue.InnerText = encryptedValue;
                    cipherData.AppendChild(cipherValue);
                    encryptedData.AppendChild(cipherData);

                    encryptedAttribute.AppendChild(encryptedData);

                    toReplace.Add((attr, encryptedAttribute));
                }

                foreach (var (original, replacement) in toReplace)
                {
                    attrStatement.ReplaceChild(replacement, original);
                }
            }

            return samlDoc;
        }

        /// <summary>
        /// Encrypts the entire SAML Assertion element using XML Encryption with TripleDES.
        /// </summary>
        public XmlDocument EncryptSamlAssertion(XmlDocument samlDoc, byte[] tripleDesKey, byte[] tripleDesIv)
        {
            const string SamlAssertionNamespace = "urn:oasis:names:tc:SAML:2.0:assertion";
            const string XencNamespace = "http://www.w3.org/2001/04/xmlenc#";

            var assertions = samlDoc.GetElementsByTagName("Assertion", SamlAssertionNamespace);
            if (assertions.Count == 0)
                return samlDoc;

            var assertion = assertions[0];
            var assertionXml = assertion.OuterXml;
            var encryptedValue = EncryptWithTripleDes(assertionXml, tripleDesKey, tripleDesIv);

            // Create EncryptedAssertion element
            var encryptedAssertion = samlDoc.CreateElement("saml", "EncryptedAssertion", SamlAssertionNamespace);

            var encryptedData = samlDoc.CreateElement("xenc", "EncryptedData", XencNamespace);
            encryptedData.SetAttribute("xmlns:xenc", XencNamespace);
            encryptedData.SetAttribute("Type", "http://www.w3.org/2001/04/xmlenc#Element");

            var encryptionMethod = samlDoc.CreateElement("xenc", "EncryptionMethod", XencNamespace);
            encryptionMethod.SetAttribute("Algorithm", "http://www.w3.org/2001/04/xmlenc#tripledes-cbc");
            encryptedData.AppendChild(encryptionMethod);

            var cipherData = samlDoc.CreateElement("xenc", "CipherData", XencNamespace);
            var cipherValueElem = samlDoc.CreateElement("xenc", "CipherValue", XencNamespace);
            cipherValueElem.InnerText = encryptedValue;
            cipherData.AppendChild(cipherValueElem);
            encryptedData.AppendChild(cipherData);

            encryptedAssertion.AppendChild(encryptedData);

            assertion.ParentNode.ReplaceChild(encryptedAssertion, assertion);

            return samlDoc;
        }

        private XmlNamespaceManager CreateNamespaceManager(XmlDocument doc)
        {
            var nsManager = new XmlNamespaceManager(doc.NameTable);
            nsManager.AddNamespace("saml", "urn:oasis:names:tc:SAML:2.0:assertion");
            nsManager.AddNamespace("samlp", "urn:oasis:names:tc:SAML:2.0:protocol");
            nsManager.AddNamespace("xenc", "http://www.w3.org/2001/04/xmlenc#");
            return nsManager;
        }
    }

