    [ApiController]
    [Route("api/[controller]")]
    public class SamlController : ControllerBase
    {
        private readonly SamlService _samlService;
        private readonly SamlEncryptionService _encryptionService;

        // In production, load from secure key store / certificate store
        private static readonly RSA _rsaKey;
        private static readonly X509Certificate2 _certificate;
        private static byte[] _tripleDesKey;
        private static byte[] _tripleDesIv;
        private static byte[] _desKey;
        private static byte[] _desIv;

        static SamlController()
        {
            // Generate a self-signed certificate for demonstration
            var rsaKeyPair = RSA.Create(2048);
            var request = new CertificateRequest(
                "CN=Enterprise SSO SP, O=Enterprise Corp, C=US",
                rsaKeyPair,
                HashAlgorithmName.SHA256,
                RSASignaturePadding.Pkcs1);

            request.CertificateExtensions.Add(
                new X509BasicConstraintsExtension(false, false, 0, false));
            request.CertificateExtensions.Add(
                new X509KeyUsageExtension(
                    X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment, false));

            _certificate = request.CreateSelfSigned(
                DateTimeOffset.UtcNow, DateTimeOffset.UtcNow.AddYears(2));
            _rsaKey = _certificate.GetRSAPrivateKey();

            // Generate encryption keys
            using var tripleDes = TripleDES.Create();
            tripleDes.GenerateKey();
            tripleDes.GenerateIV();
            _tripleDesKey = tripleDes.Key;
            _tripleDesIv = tripleDes.IV;

            using var des = DES.Create();
            des.GenerateKey();
            des.GenerateIV();
            _desKey = des.Key;
            _desIv = des.IV;
        }

        public SamlController(SamlService samlService, SamlEncryptionService encryptionService)
        {
            _samlService = samlService;
            _encryptionService = encryptionService;
        }

        /// <summary>
        /// Generate a signed SAML AuthnRequest
        /// </summary>
        [HttpPost("authn-request")]
        public IActionResult GenerateAuthnRequest([FromBody] SamlAuthnRequestModel model)
        {
            var config = new SamlConfiguration
            {
                Issuer = model?.Issuer ?? "https://sp.enterprise.com",
                IdpSsoUrl = model?.IdpSsoUrl ?? "https://idp.enterprise.com/sso",
                AssertionConsumerServiceUrl = model?.AssertionConsumerServiceUrl ?? "https://sp.enterprise.com/acs",
                NameIdFormat = model?.NameIdFormat ?? "urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            };

            var doc = _samlService.GenerateAuthnRequest(config);
            var signedDoc = _samlService.SignSamlDocument(doc, _rsaKey, _certificate);

            var base64Request = _samlService.EncodeAuthnRequestForPost(signedDoc);
            var redirectEncoded = _samlService.EncodeAuthnRequestForRedirect(signedDoc);

            return Ok(new
            {
                RawXml = signedDoc.OuterXml,
                Base64Encoded = base64Request,
                RedirectUrl = $"{config.IdpSsoUrl}?SAMLRequest={redirectEncoded}",
                SignatureValid = _samlService.VerifySignature(signedDoc)
            });
        }

        /// <summary>
        /// Generate a SAML Response with encrypted attributes and signed assertion
        /// </summary>
        [HttpPost("saml-response")]
        public IActionResult GenerateSamlResponse([FromBody] SamlResponseRequestModel model)
        {
            if (model == null || string.IsNullOrEmpty(model.NameId))
                return BadRequest("NameId is required");

            var config = new SamlConfiguration();

            var attributes = model.Attributes ?? new Dictionary<string, string>
            {
                { "email", model.NameId },
                { "firstName", "John" },
                { "lastName", "Doe" },
                { "role", "admin" },
                { "employeeId", "EMP-12345" },
                { "department", "Engineering" },
                { "ssn", "123-45-6789" }
            };

            var doc = _samlService.GenerateSamlResponseWithAttributes(config, model.NameId, attributes);

            // Sign the document
            var signedDoc = _samlService.SignSamlDocument(doc, _rsaKey, _certificate);

            // Encrypt sensitive attributes if specified
            if (model.SensitiveAttributeNames != null && model.SensitiveAttributeNames.Count > 0)
            {
                var sensitiveAttrs = model.SensitiveAttributeNames.ToDictionary(k => k, v => v);

                if (model.EncryptionAlgorithm?.ToUpper() == "DES")
                {
                    signedDoc = _encryptionService.EncryptSamlAttributes(signedDoc, sensitiveAttrs, _desKey, _desIv);
                }
                else
                {
                    signedDoc = _encryptionService.EncryptSamlAttributes(signedDoc, sensitiveAttrs, _tripleDesKey, _tripleDesIv);
                }
            }

            // Encrypt entire assertion if requested
            if (model.EncryptAssertion)
            {
                signedDoc = _encryptionService.EncryptSamlAssertion(signedDoc, _tripleDesKey, _tripleDesIv);
            }

            var base64Response = _samlService.EncodeAuthnRequestForPost(signedDoc);

            return Ok(new
            {
                RawXml = signedDoc.OuterXml,
                Base64Encoded = base64Response,
                EncryptionAlgorithm = model.EncryptionAlgorithm ?? "3DES",
                SensitiveAttributesEncrypted = model.SensitiveAttributeNames,
                AssertionEncrypted = model.EncryptAssertion
            });
        }

        /// <summary>
        /// Encrypt a single attribute value
        /// </summary>
        [HttpPost("encrypt-attribute")]
        public IActionResult EncryptAttribute([FromBody] EncryptAttributeModel model)
        {
            if (model == null || string.IsNullOrEmpty(model.Value))
                return BadRequest("Value is required");

            string encrypted;
            string algorithm;

            if (model.Algorithm?.ToUpper() == "DES")
            {
                encrypted = _encryptionService.EncryptWithDes(model.Value, _desKey, _desIv);
                algorithm = "DES";
            }
            else
            {
                encrypted = _encryptionService.EncryptWithTripleDes(model.Value, _tripleDesKey, _tripleDesIv);
                algorithm = "3DES";
            }

            return Ok(new
            {
                OriginalValue = model.Value,
                EncryptedValue = encrypted,
                Algorithm = algorithm
            });
        }

        /// <summary>
        /// Decrypt a single attribute value
        /// </summary>
        [HttpPost("decrypt-attribute")]
        public IActionResult DecryptAttribute([FromBody] DecryptAttributeModel model)
        {
            if (model == null || string.IsNullOrEmpty(model.EncryptedValue))
                return BadRequest("EncryptedValue is required");

            try
            {
                string decrypted;

                if (model.Algorithm?.ToUpper() == "DES")
                {
                    decrypted = _encryptionService.DecryptWithDes(model.EncryptedValue, _desKey, _desIv);
                }
                else
                {
                    decrypted = _encryptionService.DecryptWithTripleDes(model.EncryptedValue, _tripleDesKey, _tripleDesIv);
                }

                return Ok(new
                {
                    DecryptedValue = decrypted,
                    Algorithm = model.Algorithm ?? "3DES"
                });
            }
            catch (CryptographicException ex)
            {
                return BadRequest($"Decryption failed: {ex.Message}");
            }
        }

        /// <summary>
        /// Generate SSO redirect with auto-post form
        /// </summary>
        [HttpGet("sso-redirect")]
        public IActionResult SsoRedirect([FromQuery] string idpUrl = null)
        {
            var config = new SamlConfiguration
            {
                IdpSsoUrl = idpUrl ?? "https://idp.enterprise.com/sso"
            };

            var doc = _samlService.GenerateAuthnRequest(config);
            var signedDoc = _samlService.SignSamlDocument(doc, _rsaKey, _certificate);
            var base64Request = _samlService.EncodeAuthnRequestForPost(signedDoc);

            var html = $@"
<!DOCTYPE html>
<html>
<head><title>SSO Redirect</title></head>
<body onload=""document.forms[0].submit()"">
    <noscript>
        <p>JavaScript is disabled. Click the button below to continue.</p>
    </noscript>
    <form method=""POST"" action=""{config.IdpSsoUrl}"">
        <input type=""hidden"" name=""SAMLRequest"" value=""{base64Request}"" />
        <input type=""hidden"" name=""RelayState"" value=""{Uri.EscapeDataString("https://sp.enterprise.com/dashboard")}"" />
        <noscript>
            <input type=""submit"" value=""Continue to SSO"" />
        </noscript>
    </form>
</body>
</html>";

            return Content(html, "text/html");
        }

        /// <summary>
        /// Get metadata about the SP including certificate info
        /// </summary>
        [HttpGet("metadata")]
        public IActionResult GetMetadata()
        {
            var config = new SamlConfiguration();
            var certBase64 = Convert.ToBase64String(_certificate.RawData);

            var metadataXml = $@"<?xml version=""1.0"" encoding=""UTF-8""?>
<md:EntityDescriptor xmlns:md=""urn:oasis:names:tc:SAML:2.0:metadata""
                     entityID=""{config.Issuer}""
                     validUntil=""{DateTime.UtcNow.AddYears(1):yyyy-MM-ddTHH:mm:ssZ}"">
    <md:SPSSODescriptor AuthnRequestsSigned=""true""
                        WantAssertionsSigned=""true""
                        protocolSupportEnumeration=""urn:oasis:names:tc:SAML:2.0:protocol"">
        <md:KeyDescriptor use=""signing"">
            <ds:KeyInfo xmlns:ds=""http://www.w3.org/2000/09/xmldsig#"">
                <ds:X509Data>
                    <ds:X509Certificate>{certBase64}</ds:X509Certificate>
                </ds:X509Data>
            </ds:KeyInfo>
        </md:KeyDescriptor>
        <md:KeyDescriptor use=""encryption"">
            <ds:KeyInfo xmlns:ds=""http://www.w3.org/2000/09/xmldsig#"">
                <ds:X509Data>
                    <ds:X509Certificate>{certBase64}</ds:X509Certificate>
                </ds:X509Data>
            </ds:KeyInfo>
            <md:EncryptionMethod Algorithm=""http://www.w3.org/2001/04/xmlenc#tripledes-cbc""/>
        </md:KeyDescriptor>
        <md:NameIDFormat>{config.NameIdFormat}</md:NameIDFormat>
        <md:AssertionConsumerService Binding=""{config.ProtocolBinding}""
                                     Location=""{config.AssertionConsumerServiceUrl}""
                                     index=""0""
                                     isDefault=""true""/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>";

            return Content(metadataXml, "application/xml");
        }

        /// <summary>
        /// Health check and configuration info
        /// </summary>
        [HttpGet("info")]
        public IActionResult GetInfo()
        {
            return Ok(new
            {
                ServiceName = "Enterprise SSO SAML Service",
                Version = "1.0.0",
                SignatureAlgorithm = "RSA-SHA1 (Legacy Compatible)",
                SupportedEncryption = new[] { "DES", "3DES (TripleDES)" },
                CertificateSubject = _certificate.Subject,
                CertificateThumbprint = _certificate.Thumbprint,
                CertificateExpiry = _certificate.NotAfter,
                SamlVersion = "2.0",
                Endpoints = new
                {
                    GenerateAuthnRequest = "POST /api/saml/authn-request",
                    GenerateSamlResponse = "POST /api/saml/saml-response",
                    EncryptAttribute = "POST /api/saml/encrypt-attribute",
                    DecryptAttribute = "POST /api/saml/decrypt-attribute",
                    SsoRedirect = "GET /api/saml/sso-redirect",
                    Metadata = "GET /api/saml/metadata"
                }
            });
        }
    }

    public class EncryptAttributeModel
    {
        public string Value { get; set; }
        public string Algorithm { get; set; } = "3DES";
    }

    public class DecryptAttributeModel
    {
        public string EncryptedValue { get; set; }
        public string Algorithm { get; set; } = "3DES";
    }
}